      import sailpoint.object.Identity;
      import sailpoint.tools.Util;
      import org.apache.commons.logging.Log;
      import org.apache.commons.logging.LogFactory;

      private Log logger = LogFactory.getLog("rule.creation.ad");

      String identityName = account.getAttribute("sAMAccountName");

      if(Util.isNotNullOrEmpty(identityName)){
         logger.trace("setting name to: " + identityName);
         identity.setName(identityName.toLowerCase());
      }
      identity.setAttribute("authSourceAppName", application.getName()) ;
